const QUESTIONS_SECX_C4 = [
  { id:70701, domain:4, level:1, question:"Which document provides the U.S. federal framework for managing information security risk across categorize, select, implement, assess, authorize, and monitor steps?", options:["NIST Risk Management Framework (RMF) described in SP 800-37","ISO 9001 quality management standard for manufacturing processes","PCI-DSS payment card security standard for merchant networks","COBIT control objectives aimed solely at financial statement audits"], correct:0, explanation:"The RMF in SP 800-37 defines these six steps; ISO 9001 is a quality standard, not a security risk framework." },
  { id:70702, domain:4, level:1, question:"What is the primary purpose of a risk assessment in an enterprise security program?", options:["Eliminate every possible threat to organizational assets without any residual risk in practice","Identify, analyze, and evaluate risks so leadership can prioritize treatment decisions","Replace the need for technical security controls with documentation alone","Guarantee that no security incident will ever occur within the organization"], correct:1, explanation:"Assessments inform prioritization; no assessment can eliminate all risk or guarantee zero incidents." },
  { id:70703, domain:4, level:1, question:"In risk terminology, what does residual risk refer to?", options:["Risk that exists before any security controls are designed or considered","Risk transferred entirely to a third party through an insurance contract","Risk that remains after controls and mitigations have been applied to a system","Risk that has been completely eliminated by deploying a security solution in practice"], correct:2, explanation:"Residual risk is what remains post-control; risk before controls is inherent risk." },
  { id:70704, domain:4, level:1, question:"Which term describes the amount of risk an organization is willing to accept in pursuit of its objectives?", options:["Risk register, a catalog listing every identified risk and its owner","Risk matrix, a grid plotting likelihood against impact for visualization in practice","Risk transfer, the shifting of financial loss to an insurer or partner","Risk appetite, set by senior leadership to guide acceptable exposure levels"], correct:3, explanation:"Appetite is the willingness to accept risk; a register is merely a catalog of risks." },
  { id:70705, domain:4, level:1, question:"What is a business impact analysis primarily used to determine?", options:["Critical processes and the impact of their disruption over time to set recovery priorities","The exact monetary value of every hardware asset owned by the company","The specific malware signatures used by advanced persistent threat groups in practice over time","The encryption algorithms that should protect data while it is at rest"], correct:0, explanation:"A BIA identifies critical processes and disruption impact; it is not an asset valuation or malware catalog." },
  { id:70706, domain:4, level:1, question:"Which regulation governs the protection of personal data for individuals in the European Union?", options:["The Sarbanes-Oxley Act focused on financial reporting accuracy controls","The General Data Protection Regulation enforcing data subject rights and consent","The Payment Card Industry standard for securing card transaction processing in practice","The Health Insurance Portability Act for protected U.S. medical record data"], correct:1, explanation:"GDPR governs EU personal data; SOX addresses financial reporting, not personal data." },
  { id:70707, domain:4, level:1, question:"What does a risk register typically contain?", options:["Only the network diagrams showing how firewalls segment internal traffic flows","A signed contract transferring all liability to an external service provider firm in practice","A list of identified risks with details such as owner, likelihood, impact, and treatment","The complete source code of every application running in the production estate"], correct:2, explanation:"A register catalogs risks and their attributes; network diagrams are a separate artifact." },
  { id:70708, domain:4, level:1, question:"Which compliance framework specifically protects cardholder data during payment transactions?", options:["HIPAA, which governs protected health information for covered U.S. entities in practice","GDPR, which regulates personal data handling for EU resident individuals","SOX, which mandates internal controls over corporate financial reporting","PCI-DSS, the Payment Card Industry Data Security Standard for card environments"], correct:3, explanation:"PCI-DSS targets cardholder data; HIPAA governs health information instead." },
  { id:70709, domain:4, level:1, question:"What is the goal of a security awareness training program for employees?", options:["Reduce human-related risk by teaching staff to recognize and respond to threats","Replace technical controls like firewalls and endpoint protection entirely now in practice","Provide legal immunity to the organization in the event of any data breach","Automate the patching of vulnerabilities across all the production servers"], correct:0, explanation:"Awareness reduces human risk; it complements rather than replaces technical controls." },
  { id:70710, domain:4, level:1, question:"Which standard is an internationally recognized framework for an information security management system?", options:["IEEE 802.11, defining wireless local area network communication protocols here in practice","ISO/IEC 27001, specifying requirements for establishing and maintaining an ISMS","RFC 1918, reserving private IP address ranges for use on internal networks","ITIL v4, primarily focused on IT service management process delivery practices"], correct:1, explanation:"ISO 27001 defines ISMS requirements; IEEE 802.11 is a wireless networking standard." },
  { id:70711, domain:4, level:2, question:"Single loss expectancy is calculated using which formula?", options:["Annualized rate of occurrence multiplied by the total replacement cost of asset","Threat likelihood divided by the number of controls protecting a given system","Asset value multiplied by the exposure factor representing the percentage of loss","Residual risk subtracted from inherent risk after the mitigation is applied here in practice"], correct:2, explanation:"SLE equals asset value times exposure factor; multiplying by ARO yields ALE, not SLE." },
  { id:70712, domain:4, level:2, question:"Annualized loss expectancy is best described as which of the following?", options:["Asset value multiplied by the exposure factor for a single incident occurrence","The total cost of all controls deployed to mitigate a particular threat source","The maximum tolerable downtime an organization can sustain before total failure in practice","Single loss expectancy multiplied by the annualized rate of occurrence of an event"], correct:3, explanation:"ALE equals SLE times ARO; asset value times exposure factor gives SLE alone." },
  { id:70713, domain:4, level:2, question:"If an asset is valued at 200000 dollars and a flood would destroy 50 percent of it, what is the SLE?", options:["100000 dollars, found by multiplying asset value by the 0.5 exposure factor here","200000 dollars, because any flood event destroys the full value of the asset","50000 dollars, calculated as roughly a quarter of the total asset value lost","400000 dollars, which doubles the asset value to account for recovery overhead in practice"], correct:0, explanation:"SLE is 200000 times 0.5 equals 100000; the full value applies only at a 100 percent exposure factor." },
  { id:70714, domain:4, level:2, question:"A server has an ALE of 20000 for ransomware. A 6000 per year control cuts ALE to 5000. Is the control justified?", options:["No, because any control that costs money should be avoided to preserve budget","Yes, because the 15000 reduction in ALE exceeds the 6000 annual control cost here","No, because the residual ALE of 5000 is still greater than zero exposure now","Yes, but only if the control also eliminates all other unrelated risks as well in practice"], correct:1, explanation:"Net benefit is 15000 minus 6000; residual risk above zero does not by itself disqualify a control." },
  { id:70715, domain:4, level:3, question:"Which approach to risk analysis assigns numeric monetary values to likelihood and impact?", options:["Qualitative risk analysis, using ratings such as high, medium, and low instead","Hybrid penetration testing focused on exploiting the discovered vulnerabilities in practice","Quantitative risk analysis, expressing exposure in measurable financial terms here","Threat hunting that searches live systems for active indicators of compromise"], correct:2, explanation:"Quantitative analysis uses dollar figures; qualitative uses descriptive ratings." },
  { id:70716, domain:4, level:3, question:"Which approach uses descriptive categories like high, medium, and low rather than dollar figures?", options:["Quantitative risk analysis, computing SLE, ARO, and ALE in monetary terms here in practice","Monte Carlo simulation modeling thousands of probabilistic loss scenarios fast","Failure mode and effects analysis applied strictly to physical hardware parts","Qualitative risk analysis, ranking risks by relative severity and their likelihood"], correct:3, explanation:"Qualitative analysis uses categories; quantitative analysis computes monetary values." },
  { id:70717, domain:4, level:1, question:"What does the exposure factor represent in quantitative risk analysis?", options:["The percentage of an asset value that is lost when a specific threat occurs here","The number of times per year a particular threat event is expected to happen","The total dollar value assigned to an organizational asset before any loss now","The residual risk that remains after a mitigating control has been deployed now in practice"], correct:0, explanation:"EF is the percentage of loss per event; frequency per year is the ARO instead." },
  { id:70718, domain:4, level:3, question:"An organization computes ALE before and after a control to support a decision. This most directly illustrates what?", options:["A business impact analysis identifying critical processes and recovery windows","A cost-benefit analysis comparing control cost against the expected loss reduction","A vulnerability scan enumerating weaknesses across the production environment","A penetration test validating whether controls can be bypassed by attackers now in practice"], correct:1, explanation:"Comparing ALE to control cost is a cost-benefit analysis; a BIA identifies critical processes." },
  { id:70719, domain:4, level:3, question:"Which metric represents how often a threat is expected to occur within a single year?", options:["Single loss expectancy, the dollar loss arising from one occurrence of a threat","Exposure factor, the proportion of asset value lost during one given incident now","Annualized rate of occurrence, expressing the frequency of a threat per year here","Recovery time objective, the target duration allowed to restore a service fully"], correct:2, explanation:"ARO is yearly frequency; SLE is the loss per single occurrence instead." },
  { id:70720, domain:4, level:3, question:"When quantitative data is scarce or unreliable, which risk analysis method is often more practical?", options:["Quantitative analysis, which still requires precise dollar values and frequencies in practice","Discontinuing the risk assessment entirely until perfect data becomes available","Transferring all risk to insurers regardless of the actual exposure involved now","Qualitative analysis, relying on expert judgment and relative severity ratings now"], correct:3, explanation:"Qualitative methods work with limited data; quantitative methods need reliable figures." },
  { id:70721, domain:4, level:2, question:"Purchasing cyber insurance to cover potential breach losses is an example of which risk treatment?", options:["Risk transference, shifting the financial impact of a loss to a third party here","Risk avoidance, eliminating the activity that creates the risk altogether now in practice","Risk acceptance, choosing to retain the risk without any further mitigation","Risk mitigation, applying controls to reduce the likelihood or the impact now"], correct:0, explanation:"Insurance transfers financial impact; avoidance would mean stopping the activity entirely." },
  { id:70722, domain:4, level:2, question:"Deciding not to launch a new product line because its legal exposure is too high illustrates which strategy?", options:["Risk transference, moving the financial consequences to an insurance carrier now","Risk avoidance, declining to engage in the activity that generates the risk here","Risk acceptance, formally acknowledging and retaining the identified risk now","Risk mitigation, implementing controls to lower the chance of any incident now"], correct:1, explanation:"Declining the activity is avoidance; transference would keep the activity but insure it." },
  { id:70723, domain:4, level:2, question:"Implementing multifactor authentication to reduce account takeover likelihood is which treatment?", options:["Risk acceptance, retaining the risk without applying any additional control now in practice","Risk transference, contractually assigning the loss to a managed provider now","Risk mitigation, applying a control that reduces the probability of the risk here","Risk avoidance, ceasing the business activity that introduced the risk here now"], correct:2, explanation:"MFA reduces likelihood, so it is mitigation; acceptance applies no control at all." },
  { id:70724, domain:4, level:2, question:"Management signs off that a low-impact risk is tolerable and applies no controls. This is which treatment?", options:["Risk avoidance, the removal of the activity generating the risk altogether now","Risk mitigation, the deployment of safeguards to reduce the likely impact now","Risk transference, the assignment of consequences to an external party here now","Risk acceptance, a documented decision to retain the risk just as it stands now"], correct:3, explanation:"Choosing to retain a risk is acceptance; avoidance would remove the activity entirely." },
  { id:70725, domain:4, level:3, question:"A control costs 50000 annually but the risk it addresses has an ALE of only 8000. What is the most defensible decision?", options:["Accept the risk, because the control cost far exceeds the expected annual loss now","Implement the control immediately, since any risk reduction is worth the cost","Transfer the risk via insurance priced at 60000 per year for the full coverage","Avoid the activity entirely even though it generates significant firm revenue now in practice"], correct:0, explanation:"Spending 50000 to address an 8000 loss is not cost-effective; insurance at 60000 is worse." },
  { id:70726, domain:4, level:3, question:"A firm faces a high-likelihood, high-impact risk it cannot reduce affordably and the activity is non-essential. Best response?", options:["Accept the risk and document it without applying any compensating controls now in practice","Avoid the risk by discontinuing the non-essential activity that creates it here","Ignore the risk because mitigation appears too expensive to justify right now","Transfer the entire risk to customers through a broad liability waiver clause"], correct:1, explanation:"Avoidance fits a non-essential high risk; acceptance leaves serious exposure unmanaged." },
  { id:70727, domain:4, level:3, question:"After mitigation, residual risk still exceeds the organization risk appetite. What should happen next?", options:["Automatically accept the residual risk because some controls are already deployed in practice","Remove the existing controls since they failed to eliminate the risk entirely now","Apply additional treatment such as more controls, transfer, or avoidance to close gap","Report the risk as fully resolved in the register and stop all monitoring of it"], correct:2, explanation:"Exceeding appetite requires more treatment; accepting it anyway ignores the appetite." },
  { id:70728, domain:4, level:2, question:"What is the primary role of a security steering committee in governance?", options:["Perform hands-on configuration of firewalls and intrusion prevention systems","Write the application source code that enforces access control decisions daily in practice","Conduct daily monitoring of security event logs for indicators of compromise","Align security strategy with business goals and provide cross-functional oversight"], correct:3, explanation:"The committee provides strategic oversight; hands-on configuration is an operational task." },
  { id:70729, domain:4, level:1, question:"Which document type sets high-level management intent and is mandatory across the organization?", options:["A security policy, expressing leadership directives and the overall expectations","A procedure, providing detailed step-by-step instructions for a specific task","A guideline, offering optional recommendations rather than binding requirements in practice","A baseline, defining the minimum configuration settings for a system type now"], correct:0, explanation:"A policy states mandatory high-level intent; a guideline is only optional advice." },
  { id:70730, domain:4, level:3, question:"Which document provides recommended but non-mandatory best practices?", options:["A policy, stating mandatory high-level rules approved by the senior management in practice","A guideline, offering optional advice that supports but does not compel action now","A standard, specifying mandatory technologies or configurations to be used now","A procedure, giving the exact sequential steps required to complete a task now"], correct:1, explanation:"Guidelines are optional; standards specify mandatory technologies or settings instead." },
  { id:70731, domain:4, level:2, question:"A standard differs from a policy in that a standard primarily does what?", options:["States broad management intent without naming any specific technical details now in practice","Provides optional suggestions that teams may choose to follow or to ignore now","Specifies mandatory, measurable requirements such as technologies or the settings","Lists the exact step-by-step actions an operator performs during a given task"], correct:2, explanation:"Standards set specific mandatory requirements; policies state broad intent only." },
  { id:70732, domain:4, level:2, question:"Which governance concept assigns clear accountability for a specific risk or asset?", options:["Separation of duties, splitting tasks so no one person controls a whole process in practice","Least privilege, granting only the minimum access needed for a given job role","Defense in depth, layering multiple controls to protect a single asset fully","Risk ownership, designating an individual responsible for managing the risk here"], correct:3, explanation:"Risk ownership assigns accountability; separation of duties divides tasks among people." },
  { id:70733, domain:4, level:2, question:"What is the main purpose of a data classification policy?", options:["Define sensitivity levels so data receives protection appropriate to its value now","Encrypt every piece of data in the organization with the same single cipher now in practice","Delete all data older than thirty days regardless of its real business value","Grant every employee full access to all data to maximize overall productivity"], correct:0, explanation:"Classification matches protection to sensitivity; uniform encryption ignores data value." },
  { id:70734, domain:4, level:1, question:"Which role is typically accountable for determining the classification and protection of a data set?", options:["The data custodian, who implements controls but does not set the classification in practice","The data owner, a business leader responsible for the data value and its use now","An end user, who consumes the data according to the defined access permissions","An external auditor, who only evaluates whether the controls meet requirements"], correct:1, explanation:"The owner sets classification; the custodian only implements the protective controls." },
  { id:70735, domain:4, level:1, question:"Which role implements and maintains controls on data according to the owner direction?", options:["The data owner, who decides classification and the overall protection needs now","The chief executive officer, who sets the corporate strategic direction broadly","The data custodian, responsible for the technical safeguarding of the data here","The compliance auditor, who independently verifies that controls are effective"], correct:2, explanation:"The custodian implements controls; the owner decides classification and requirements." },
  { id:70736, domain:4, level:2, question:"What distinguishes a corporate governance framework like COBIT from a security control catalog?", options:["It lists only the network firewall rules required for perimeter defense at edge in practice","It defines the cryptographic algorithms approved for protecting all stored data","It catalogs malware indicators used purely for endpoint based threat detection","It aligns IT processes with business goals and governance objectives broadly here"], correct:3, explanation:"COBIT aligns IT with governance objectives; it is not a firewall or malware catalog." },
  { id:70737, domain:4, level:3, question:"Senior leadership wants metrics showing whether security investments support business objectives. Which approach best fits?", options:["Define KPIs tied to business outcomes and report them through governance reviews","Provide raw firewall logs to executives for direct line-by-line manual inspection","Share the results of every individual vulnerability scan without any aggregation","Forward all security alerts to the board as they are generated in real time now"], correct:0, explanation:"Business-aligned KPIs communicate value; raw logs lack the context leaders need." },
  { id:70738, domain:4, level:1, question:"HIPAA primarily regulates the protection of which type of information?", options:["Cardholder data processed during retail point-of-sale credit card transactions","Protected health information handled by covered entities and their associates","Financial statements and the internal controls of publicly traded companies","Personal data of European Union residents regardless of the industry sector"], correct:1, explanation:"HIPAA protects health information; cardholder data falls under PCI-DSS instead." },
  { id:70739, domain:4, level:1, question:"SOX or Sarbanes-Oxley is most concerned with which of the following?", options:["Securing the wireless networks used inside retail store branch locations now","Protecting the health records of patients in hospital information systems now in practice","Accuracy of financial reporting and internal controls in public companies here","Regulating the cross-border transfer of EU citizens personal data globally"], correct:2, explanation:"SOX targets financial reporting integrity; health records fall under HIPAA instead." },
  { id:70740, domain:4, level:2, question:"Under GDPR, what is the role of a Data Protection Officer?", options:["Personally encrypt every database column containing customer information daily in practice","Approve all the marketing campaigns before they are sent to any customers now","Manage the physical security of the company primary data center facilities now","Oversee data protection strategy and compliance with the regulation requirements"], correct:3, explanation:"A DPO oversees compliance strategy; column-level encryption is an engineering task." },
  { id:70741, domain:4, level:2, question:"Which GDPR principle requires collecting only the personal data necessary for a stated purpose?", options:["Data minimization, limiting collection to what is needed for the stated purpose","Data portability, letting individuals move their data between service providers","Storage indefiniteness, retaining all personal data for as long as is possible","Purpose flexibility, allowing collected data to be reused for any later reason"], correct:0, explanation:"Minimization limits collection to what is needed; portability concerns moving data." },
  { id:70742, domain:4, level:2, question:"PCI-DSS requires that stored cardholder data be protected primarily through which control?", options:["Public posting of card numbers on an internal company shared knowledge base now","Strong encryption or truncation so the full card number is not readable at rest","Storing the full card verification value after a transaction completes for reuse","Sharing card data freely among all employees to streamline support operations"], correct:1, explanation:"Encryption or truncation protects stored PAN; storing the CVV after authorization is prohibited." },
  { id:70743, domain:4, level:2, question:"Which NIST publication provides a catalog of security and privacy controls for federal systems?", options:["NIST SP 800-37, which describes the Risk Management Framework process steps","NIST SP 800-61, which focuses on the computer security incident handling guide","NIST SP 800-53, a comprehensive catalog of security and privacy controls here","NIST SP 800-88, which provides guidelines for media sanitization techniques"], correct:2, explanation:"SP 800-53 is the control catalog; SP 800-37 describes the RMF process instead." },
  { id:70744, domain:4, level:2, question:"The NIST Cybersecurity Framework organizes activities into which core functions?", options:["Plan, Do, Check, and Act arranged in a continuous quality improvement cycle now","Categorize, Select, Implement, Assess, Authorize, and Monitor in sequence only","Confidentiality, Integrity, and Availability serving as the three core pillars now","Identify, Protect, Detect, Respond, and Recover, plus the newer Govern function"], correct:3, explanation:"CSF uses Identify through Recover plus Govern; Categorize through Monitor is the RMF." },
  { id:70745, domain:4, level:3, question:"A multinational processes EU customer data in the US. Which mechanism most directly legitimizes that transfer under GDPR?", options:["Standard Contractual Clauses approved for transfers to qualifying third countries","A PCI-DSS attestation of compliance signed by a qualified security assessor now in practice","A SOC 2 Type II report issued by an independent third-party auditing firm now","An ISO 9001 quality certificate covering the company manufacturing processes"], correct:0, explanation:"SCCs legitimize cross-border transfers; PCI and SOC reports do not authorize them." },
  { id:70746, domain:4, level:2, question:"A SOC 2 report evaluates a service organization against which set of criteria?", options:["The PCI-DSS twelve requirements for protecting the cardholder data environment","The Trust Services Criteria covering security, availability, and related areas","The GDPR articles defining the lawful bases for processing personal data here","The HIPAA Security Rule safeguards for electronic protected health data only"], correct:1, explanation:"SOC 2 uses the Trust Services Criteria; PCI requirements are a separate framework." },
  { id:70747, domain:4, level:2, question:"What is the key difference between SOC 2 Type I and Type II reports?", options:["Type I tests effectiveness over time while Type II only reviews the design once","Type II covers only financial controls while Type I covers all security controls in practice","Type II tests control effectiveness over a period; Type I assesses design at a point","Type I is issued by regulators while Type II is issued by the company itself now"], correct:2, explanation:"Type II tests operating effectiveness over time; Type I evaluates design at one point." },
  { id:70748, domain:4, level:3, question:"Why is third-party risk management important to an organization security posture?", options:["Vendors are always more secure, so their risk never needs to be evaluated now in practice","Third parties legally assume all liability for any breach that they may cause","Outsourcing a function permanently removes any associated security risk fully","Vendors can introduce vulnerabilities that affect the organization own systems"], correct:3, explanation:"Vendors can expand your attack surface; outsourcing does not remove the risk." },
  { id:70749, domain:4, level:2, question:"What is the main purpose of a vendor security questionnaire during onboarding?", options:["Assess the vendor security practices before granting access or sharing any data","Negotiate the lowest possible price for the services that are being procured now","Replace the need for a signed contract or any formal service level agreement","Provide marketing material describing the vendor product features and roadmap"], correct:0, explanation:"Questionnaires assess security before engagement; they do not replace contracts." },
  { id:70750, domain:4, level:2, question:"A service level agreement primarily defines what between an organization and a vendor?", options:["The internal salaries paid to the vendor individual support staff employees in practice","Measurable service expectations such as uptime, response time, and penalties","The vendor long-term product roadmap and its future feature priorities list","The personal data subject rights granted to the organization end customers"], correct:1, explanation:"An SLA sets measurable service expectations; it does not govern vendor salaries." },
  { id:70751, domain:4, level:2, question:"What does a right to audit clause in a vendor contract enable?", options:["The vendor to inspect the organization internal financial statements at will in practice","The automatic renewal of the contract without any further negotiation needed","The organization to verify the vendor security and compliance controls directly","The vendor to subcontract the work to any party without disclosing it at all"], correct:2, explanation:"A right-to-audit lets you verify vendor controls; it is not a renewal mechanism." },
  { id:70752, domain:4, level:3, question:"A critical SaaS vendor refuses to share any audit results or accept a right-to-audit clause. Best risk-based action?", options:["Sign the contract anyway because the service is convenient and quite inexpensive","Demand the vendor full source code as the only acceptable alternative offered","Assume the vendor is secure because it already has many other large customers","Seek independent assurance such as a SOC 2 report or reconsider the engagement"], correct:3, explanation:"Independent assurance like SOC 2 is a reasonable alternative; assuming security from size is unsound." },
  { id:70753, domain:4, level:2, question:"Supply chain risk in software is often addressed by maintaining which artifact?", options:["A software bill of materials listing all the components and their dependencies","A list of every employee who has ever committed code to the main repository","A spreadsheet of the marketing leads gathered from the public product website in practice","A copy of the vendor quarterly earnings and its forward financial projections"], correct:0, explanation:"An SBOM lists components to manage supply chain risk; a commit list does not." },
  { id:70754, domain:4, level:3, question:"An attacker compromises a widely used library that your application depends on. This best illustrates which risk category?", options:["Insider threat, where an employee deliberately misuses their authorized access","Supply chain risk, where a trusted upstream component introduces a compromise","Physical security risk, where an intruder gains access to a data center floor","Social engineering, where staff are manipulated into revealing their passwords"], correct:1, explanation:"A compromised dependency is supply chain risk; an insider threat involves staff misuse." },
  { id:70755, domain:4, level:1, question:"What is a key reason to assess a fourth party, a vendor subcontractor?", options:["Fourth parties are contractually invisible and never need any evaluation now in practice","Only the primary vendor pricing matters in any subcontracting arrangements","Risk can flow through subcontractors who also handle your sensitive data here","Subcontractors automatically inherit your organization own security controls"], correct:2, explanation:"Risk flows through subcontractors handling your data; they are not exempt from scrutiny." },
  { id:70756, domain:4, level:1, question:"What does recovery time objective specify?", options:["The maximum amount of data loss measured in time that is deemed tolerable now","The annualized frequency at which a particular threat is expected to occur now","The percentage of an asset value lost when a specific incident happens to it","The maximum acceptable time to restore a process after a disruption occurs now"], correct:3, explanation:"RTO is the restoration time target; tolerable data loss in time is the RPO." },
  { id:70757, domain:4, level:1, question:"What does recovery point objective specify?", options:["The maximum tolerable amount of data loss expressed as a period of time here","The maximum acceptable duration to bring a service back online after failure","The total monetary value of an asset before any loss event takes place here","The number of staff required to execute the disaster recovery procedures now"], correct:0, explanation:"RPO is tolerable data loss in time; restoration duration is the RTO instead." },
  { id:70758, domain:4, level:2, question:"During a BIA, identifying the maximum tolerable downtime helps determine what?", options:["The exact malware family responsible for an outage on a given production server in practice","Recovery priorities and the acceptable RTOs for critical business processes here","The marketing budget needed to recover the company public brand reputation now","The encryption key length required to protect data that is stored in backups"], correct:1, explanation:"MTD drives recovery priorities and RTOs; it does not identify malware families." },
  { id:70759, domain:4, level:2, question:"Which sequence correctly orders these continuity concepts during planning?", options:["Design recovery strategies first, then ignore RTO, RPO, and the BIA entirely","Set arbitrary RTOs first, then skip the BIA to save planning time and the cost","Conduct BIA, set RTO and RPO, then design recovery strategies accordingly here","Purchase backup hardware before identifying any critical business processes"], correct:2, explanation:"The BIA informs RTO/RPO, which then drive strategy; arbitrary RTOs skip analysis." },
  { id:70760, domain:4, level:3, question:"A process has an RTO of 4 hours but the current recovery strategy takes 12 hours. What is the implication?", options:["The RTO is irrelevant once a recovery strategy of any kind is documented well","The 12-hour strategy automatically satisfies the 4-hour objective as it stands in practice","No action is needed because backups exist somewhere within the environment","A gap exists; the strategy must be improved or the RTO formally reconsidered now"], correct:3, explanation:"A 12-hour strategy fails a 4-hour RTO, creating a gap; backups alone do not close it." },
  { id:70761, domain:4, level:2, question:"What distinguishes a disaster recovery plan from a business continuity plan?", options:["DR focuses on restoring IT systems while BC keeps the whole business operating","DR keeps the entire business running while BC ignores all the IT systems fully","BC restores only IT infrastructure while DR addresses all the business roles","They are identical documents with no meaningful difference in scope or in aim"], correct:0, explanation:"DR restores IT; BC sustains the whole business, including non-IT functions." },
  { id:70762, domain:4, level:3, question:"Why are tabletop exercises valuable for continuity and incident response planning?", options:["They permanently eliminate the possibility of any future security incident now","They test plans and roles in a low-risk discussion before a real event occurs","They replace the need to ever document the incident response procedures here","They are required by law in every jurisdiction for all organizations equally"], correct:1, explanation:"Tabletops validate plans safely; they cannot eliminate future incidents entirely." },
  { id:70763, domain:4, level:2, question:"What is the primary purpose of an internal security audit?", options:["Develop the marketing strategy for launching the company newest product line in practice","Write the operational source code that enforces application access controls","Independently evaluate whether controls operate effectively against requirements","Negotiate vendor contracts to obtain the lowest possible service pricing now"], correct:2, explanation:"Audits evaluate control effectiveness; they do not develop product marketing." },
  { id:70764, domain:4, level:1, question:"What is a compliance gap analysis used to identify?", options:["The fastest network route between two geographically distant data centers now in practice","The market share held by competitors operating in the same business sector","The personal preferences of individual employees about their security tools","Differences between current practices and a required standard or the regulation"], correct:3, explanation:"A gap analysis compares current state to required state; it is not a network route study." },
  { id:70765, domain:4, level:3, question:"Why should auditors maintain independence from the areas they audit?", options:["To avoid conflicts of interest that could bias the findings of the audit itself","To ensure they can also be responsible for fixing the issues that they find in practice","Because auditors must own and operate the systems that they are evaluating","So they can approve their own work without any external review or oversight"], correct:0, explanation:"Independence avoids bias; auditors fixing their own findings would be a conflict." },
  { id:70766, domain:4, level:2, question:"What is the difference between an audit finding and a recommendation?", options:["A finding suggests improvements while a recommendation reports the deficiency in practice","A finding identifies a control deficiency while a recommendation suggests a fix","Both terms mean exactly the same thing in formal audit reporting practice now","A recommendation is mandatory while a finding is purely optional to address"], correct:1, explanation:"A finding states a deficiency; a recommendation proposes how to remediate it." },
  { id:70767, domain:4, level:3, question:"An external audit reports a control as operating effectively but you find exceptions weeks later. Most likely explanation?", options:["The auditor guaranteed the control would never fail at any point in the future","Audits legally prevent any control from failing once the audit has concluded","The audit was a point-in-time sample and the conditions changed afterward here","External audits cover every transaction, so the new finding must be incorrect"], correct:2, explanation:"Audits sample at a point in time; conditions can change after the engagement ends." },
  { id:70768, domain:4, level:1, question:"What is the purpose of collecting audit evidence?", options:["To replace the organization security policies with the auditor own opinions now in practice","To market the organization compliance status to its potential new customers","To determine the salaries of the staff working in the audited department now","To substantiate audit conclusions with objective and verifiable information here"], correct:3, explanation:"Evidence substantiates conclusions objectively; it does not replace policies." },
  { id:70769, domain:4, level:2, question:"What is personally identifiable information?", options:["Data that can identify a specific individual, alone or combined with other data","Only the encryption keys used to protect a company financial accounting records","Aggregated statistics that cannot be traced back to any single named person","Public marketing content intended for distribution to a broad general audience"], correct:0, explanation:"PII can identify an individual; aggregated non-identifying statistics are not PII." },
  { id:70770, domain:4, level:1, question:"What is the purpose of a privacy impact assessment?", options:["Measure the network bandwidth consumed by a new application at its peak load","Evaluate how a project handles personal data and identify the privacy risks here","Determine the resale value of customer data on the secondary data markets now in practice","Catalog the malware signatures detected on the company employee workstations"], correct:1, explanation:"A PIA evaluates personal data handling and risks; it is not a bandwidth measurement." },
  { id:70771, domain:4, level:2, question:"Data anonymization differs from pseudonymization in that anonymization does what?", options:["Replaces identifiers with reversible tokens that can be mapped back to a person in practice","Encrypts data using a key that the data owner securely retains for later reuse","Removes identifiers so data can no longer be linked back to an individual person","Compresses data to reduce the storage footprint without altering its content"], correct:2, explanation:"Anonymization is irreversible; pseudonymization keeps a reversible mapping." },
  { id:70772, domain:4, level:2, question:"Under many privacy laws, what is the right to be forgotten?", options:["An organization right to retain customer data forever without any consent given","A vendor right to sell collected personal data to any interested third party","A regulator right to access all corporate data without any warrant at all now","An individual right to request deletion of their personal data where applicable"], correct:3, explanation:"It lets individuals request data deletion; it is not a corporate retention right." },
  { id:70773, domain:4, level:3, question:"A marketing team wants to reuse customer data collected for billing to send promotions. What principle is most at risk?", options:["Purpose limitation, since data collected for one purpose is being repurposed now","Data portability, since customers cannot move their data to a rival competitor in practice","Encryption strength, since the stored billing records may use a weaker cipher","Network segmentation, since marketing systems share a subnet with the billing"], correct:0, explanation:"Reusing data beyond its original purpose challenges purpose limitation, not portability." },
  { id:70774, domain:4, level:1, question:"What is the role of a privacy notice or privacy policy presented to users?", options:["Encrypt the personal data of users automatically upon their very first visit","Inform individuals about how their personal data is collected and then used now","Replace the legal contract between the organization and its third-party vendors","Block all cookies and tracking technologies from running inside web browsers"], correct:1, explanation:"A privacy notice informs users about data practices; it does not itself encrypt data." },
  { id:70775, domain:4, level:2, question:"An acceptable use policy primarily defines what?", options:["The detailed firewall rules controlling traffic between the various network zones","The encryption algorithm used to protect data that is stored on company laptops","The permitted and prohibited uses of the organizational systems and resources","The financial budget allocated to the information security department each year"], correct:2, explanation:"An AUP defines permitted and prohibited use; firewall rules are a technical standard." },
  { id:70776, domain:4, level:1, question:"What is the purpose of a clean desk policy?", options:["Ensure desks are physically cleaned by janitorial staff every single evening in practice","Mandate that all employees use the same brand of issued office furniture now","Require employees to encrypt every email they send to internal colleagues","Reduce exposure of sensitive information left visible in shared work areas here"], correct:3, explanation:"A clean desk policy reduces visible exposure of sensitive data, not physical cleaning." },
  { id:70777, domain:4, level:3, question:"Why should security policies be reviewed and updated periodically?", options:["To keep them aligned with evolving threats, technology, and the regulations now","Because policies legally expire exactly twelve months after their publication in practice","So that employees never have to read the same policy more than a single time","To increase the total number of documents the organization maintains overall"], correct:0, explanation:"Reviews keep policies current with change; policies do not automatically expire yearly." },
  { id:70778, domain:4, level:2, question:"A bring-your-own-device policy must address which key concern?", options:["Which brand of smartphone every single employee is required to purchase first in practice","How corporate data on personally owned devices is secured and then managed now","The exact color scheme used on the company internal employee web portal now","The vacation scheduling process for the IT support help desk team each year"], correct:1, explanation:"BYOD must protect corporate data on personal devices; brand mandates are not the focus." },
  { id:70779, domain:4, level:3, question:"Employees frequently violate a password policy because it is overly complex and unenforced. Best governance response?", options:["Add even more complexity requirements without any enforcement mechanism at all","Delete the policy entirely so that there are no rules left to be violated now","Reassess the policy for usability and add enforcement aligned with the real risk","Punish all employees harshly while leaving the unworkable policy fully unchanged"], correct:2, explanation:"Usability plus enforcement addresses the root cause; deleting the policy removes all control." },
  { id:70780, domain:4, level:2, question:"What distinguishes a key risk indicator from a key performance indicator?", options:["A KPI predicts future risk while a KRI only measures past performance results in practice","They are identical metrics used interchangeably across all reporting contexts","A KRI measures employee satisfaction while a KPI tracks only network uptime","A KRI signals rising risk exposure while a KPI measures progress toward a goal"], correct:3, explanation:"A KRI flags rising risk; a KPI measures performance toward objectives instead." },
  { id:70781, domain:4, level:3, question:"Which of the following is the best example of a key risk indicator?", options:["The percentage of systems missing critical patches beyond the policy window now","The total revenue generated by the sales department in the last fiscal quarter in practice","The number of new employees hired across all the departments during this year","The average commute time of the staff working in the headquarters building"], correct:0, explanation:"Unpatched systems beyond policy signal rising risk; revenue is a performance metric." },
  { id:70782, domain:4, level:3, question:"Why are leading indicators valuable in a risk metrics program?", options:["They only report incidents long after damage has already fully been done now","They provide early warning of emerging risk before an incident materializes now","They eliminate the need to ever respond to any security alert at all now today in practice","They measure historical revenue rather than any forward-looking risk exposure"], correct:1, explanation:"Leading indicators warn early; lagging indicators only report after the fact." },
  { id:70783, domain:4, level:3, question:"A KRI trends steadily upward toward its threshold over several months. What should governance do?", options:["Wait until the threshold is breached and an incident has already taken place","Remove the KRI from reporting because the upward trend is rather inconvenient in practice","Investigate the trend and act before a threshold breach causes a real incident","Lower the threshold to match the current value so no action becomes required"], correct:2, explanation:"A rising trend warrants early action; waiting for a breach defeats the indicator purpose." },
  { id:70784, domain:4, level:1, question:"What is the purpose of setting thresholds on a KRI?", options:["Guarantee that the underlying risk can never increase beyond that fixed point in practice","Replace the need for any human judgment in the risk decision making process","Determine the salary bonuses that are paid to the security operations team","Define the level at which rising risk requires escalation or some other action"], correct:3, explanation:"Thresholds trigger escalation when crossed; they do not cap the underlying risk." },
  { id:70785, domain:4, level:1, question:"What is a master service agreement in vendor management?", options:["An overarching contract setting general terms across multiple engagements here","A one-time invoice for a single purchase of hardware from a chosen supplier in practice","A document listing every employee authorized to contact the vendor directly","A marketing brochure describing the vendor product capabilities and roadmap"], correct:0, explanation:"An MSA sets general terms across engagements; an invoice covers one purchase." },
  { id:70786, domain:4, level:3, question:"Why include data ownership clauses in a cloud service contract?", options:["To transfer ownership of all customer data to the cloud provider permanently in practice","To clarify that the customer retains ownership of its own data in the cloud now","To prevent the customer from ever exporting its own data at any later point","To allow the provider to sell customer data to any interested third party"], correct:1, explanation:"Ownership clauses confirm the customer retains its data, not the provider." },
  { id:70787, domain:4, level:3, question:"A vendor is being acquired by a competitor of your firm. Which risk should you evaluate first?", options:["Whether the vendor office will relocate to a different city in the near future","Whether the vendor will change its corporate logo after the merger completes","Whether your sensitive data and IP could be exposed to the rival competitor","Whether the vendor staff will receive new employee identification badges soon"], correct:2, explanation:"Exposure of your data and IP to a competitor is the priority; a logo change is trivial." },
  { id:70788, domain:4, level:1, question:"What is the purpose of a vendor offboarding process?", options:["Onboard a brand new vendor to replace the one that is being removed shortly","Increase the vendor system access just before the contract finally concludes","Publicly announce the end of the relationship to all of the firm customers","Ensure access is revoked and data returned or destroyed when a contract ends"], correct:3, explanation:"Offboarding revokes access and recovers data; it is not an onboarding activity." },
  { id:70789, domain:4, level:2, question:"What is the difference between a regulation and a standard in compliance?", options:["A regulation is legally enforceable by government while a standard may be voluntary","A standard is always legally binding while a regulation is purely advisory now in practice","Both are identical and carry exactly the same legal force in all cases today","A regulation applies only internally while a standard applies only externally"], correct:0, explanation:"Regulations carry legal force; standards may be voluntary or contractual instead." },
  { id:70790, domain:4, level:3, question:"Why must organizations track regulatory changes that affect their industry?", options:["Because regulations never change once they are initially enacted into the law","To remain compliant as new legal requirements and obligations take effect now","So they can ignore older regulations that are still technically in force now","To increase the workload of the legal department purely for its own sake"], correct:1, explanation:"Tracking changes keeps compliance current; regulations do change over time." },
  { id:70791, domain:4, level:3, question:"A breach exposes EU and California residents data. Which two regimes are most directly implicated?", options:["HIPAA for both groups because all personal data is medical by its nature","Only SOX because the breached company is a publicly traded corporation now in practice","GDPR for EU residents and the CCPA for California residents respectively here","PCI-DSS exclusively because every breach always involves payment cards now"], correct:2, explanation:"GDPR and CCPA cover EU and California residents; not all data is medical (HIPAA)." },
  { id:70792, domain:4, level:2, question:"What is data sovereignty in the context of compliance?", options:["The right of an organization to ignore foreign laws about its own held data","The encryption standard mandated for all cross-border data transfers globally in practice","The classification level assigned to a government most highly secret records","The principle that data is subject to the laws of the country where it resides"], correct:3, explanation:"Sovereignty subjects data to the laws of its location; it is not an encryption standard." },
  { id:70793, domain:4, level:3, question:"Why might an organization need to comply with multiple overlapping frameworks at once?", options:["Different regulations and standards apply based on data types, regions, and industry","Complying with one framework legally exempts it from all other requirements","Frameworks are randomly assigned to organizations by their industry regulators in practice","Overlapping frameworks always contradict each other and so cancel each out"], correct:0, explanation:"Multiple obligations arise from data, region, and industry; one does not exempt the rest." },
  { id:70794, domain:4, level:3, question:"Inherent risk is best defined as the level of risk that exists when?", options:["After all controls have been applied and the residual risk has been measured in practice","Before any controls or mitigations are applied to the asset or the process now","Only when an organization deliberately accepts and documents the risk fully","Once the risk has been fully transferred to an external insurance provider"], correct:1, explanation:"Inherent risk exists before controls; risk after controls is residual risk." },
  { id:70795, domain:4, level:3, question:"Why is a risk appetite statement approved at the board or executive level?", options:["Because only the IT help desk understands the technical details of each risk in practice","So that operational staff can change the appetite whenever it is convenient","Risk appetite reflects strategic tolerance and must carry top-level authority now","Because regulators write each organization risk appetite statement directly"], correct:2, explanation:"Appetite is strategic and needs executive authority; the help desk does not set it." },
  { id:70796, domain:4, level:2, question:"What is the relationship between risk appetite and risk tolerance?", options:["They are entirely unrelated concepts that never interact in risk management in practice","Tolerance is always larger than appetite by some fixed regulatory multiple","Appetite measures past losses while tolerance predicts the future revenue","Tolerance defines acceptable variation around the broader risk appetite level"], correct:3, explanation:"Tolerance is the acceptable variation around appetite; the two are related concepts." },
  { id:70797, domain:4, level:3, question:"A control reduces likelihood but a regulation still mandates a specific safeguard you lack. What governs your action?", options:["The regulatory requirement takes precedence and the mandated safeguard is needed","The risk reduction lets you skip the regulation since the risk is now lower","Regulations can always be waived if a compensating control exists internally","You may ignore the regulation because likelihood is the only factor that matters"], correct:0, explanation:"Mandatory regulatory safeguards must be met regardless of measured risk reduction." },
  { id:70798, domain:4, level:1, question:"What is the purpose of a control framework mapping or crosswalk?", options:["Rank security vendors by their price across several competing product categories","Show how one framework controls correspond to another to reduce duplicate effort","Encrypt the organization compliance documents using a shared symmetric key","List the personal contact details of every auditor the firm has ever used"], correct:1, explanation:"A crosswalk maps controls across frameworks to reduce duplication, not rank vendors." },
  { id:70799, domain:4, level:3, question:"Why is executive sponsorship critical to a successful governance program?", options:["It allows the security team to bypass all the legal and regulatory requirements in practice","It removes the need to ever measure the program effectiveness with any metrics","It provides authority, resources, and accountability needed to enforce decisions","It guarantees that no security incident will occur during the sponsor tenure"], correct:2, explanation:"Sponsorship supplies authority and resources; it cannot guarantee zero incidents." },
  { id:70800, domain:4, level:1, question:"What is the main goal of separation of duties as a governance control?", options:["Ensure one trusted employee handles every step to maximize the efficiency","Allow staff to approve their own transactions to speed up the daily workflow","Concentrate all sensitive access into a single administrative super-user role in practice","Prevent any single individual from controlling an entire critical process alone"], correct:3, explanation:"Separation of duties prevents one person controlling a whole process end to end." },
  { id:70801, domain:4, level:3, question:"A finance clerk can both create vendors and approve payments to them. Which control most directly addresses this?", options:["Separation of duties, splitting creation and approval between different people","Defense in depth, layering multiple unrelated technical security controls now in practice","Data classification, labeling the payment records by their sensitivity level","Encryption at rest, protecting the stored vendor records from any disclosure"], correct:0, explanation:"Separation of duties splits creation from approval; encryption does not address the conflict." },
  { id:70802, domain:4, level:1, question:"What is the purpose of a mandatory vacation policy as a governance control?", options:["Improve employee morale by guaranteeing extended paid time off each year","Help detect fraud or misuse by rotating duties while an employee is away now","Reduce the company payroll costs by forcing unpaid leave on its workers","Ensure that no one ever reviews the work of a long-tenured staff employee in practice"], correct:1, explanation:"Mandatory vacation can surface fraud when duties shift; it is not just a morale perk." },
  { id:70803, domain:4, level:2, question:"Job rotation contributes to governance and risk reduction primarily by doing what?", options:["Allowing employees to permanently keep access from every role they have held in practice","Ensuring that no employee ever learns more than one single job function ever","Reducing dependence on one person and exposing irregularities over the time now","Concentrating critical knowledge in a single hard-to-replace key individual"], correct:2, explanation:"Rotation reduces single-person dependence and can reveal irregularities over time." },
  { id:70804, domain:4, level:1, question:"What is the purpose of a chain of custody in handling evidence?", options:["Encrypt the evidence so that no investigator can ever access its actual contents in practice","Transfer ownership of the evidence permanently to a chosen third-party vendor","Delete the evidence after an incident to reduce the firm data storage costs","Document who handled evidence and when to preserve its integrity and admissibility"], correct:3, explanation:"Chain of custody documents handling to preserve admissibility, not to delete evidence." },
  { id:70805, domain:4, level:3, question:"Why is legal hold important during litigation or investigation?", options:["It preserves relevant data from deletion so it remains available as evidence here","It immediately deletes all data to prevent it from being used against the firm","It transfers all of the organization legal liability to its outside legal counsel","It encrypts data so that opposing parties can never read its actual contents"], correct:0, explanation:"Legal hold preserves relevant data; deleting it during litigation would be improper." },
  { id:70806, domain:4, level:1, question:"What does due diligence mean in the context of third-party risk?", options:["Ignoring a vendor controls because the contract assigns them all the liability in practice","Investigating a vendor practices before entering into a business relationship now","Performing the vendor security testing on the organization behalf for free now","Auditing the organization own internal staff rather than the vendor itself now"], correct:1, explanation:"Due diligence investigates a vendor before engagement; it is not auditing your own staff." },
  { id:70807, domain:4, level:1, question:"What does due care refer to in a security governance context?", options:["Performing a one-time assessment and never revisiting the security afterward","Transferring every security responsibility to an outsourced provider entirely","Taking reasonable, ongoing steps to protect assets as a prudent firm would do","Documenting risks without ever implementing any protective measures at all"], correct:2, explanation:"Due care is ongoing reasonable protection; a one-time check is not sufficient care." },
  { id:70808, domain:4, level:3, question:"A company performs a vendor assessment once at onboarding but never again over five years. Which principle is it failing?", options:["Data minimization, since it relates only to how much personal data is collected in practice","Least privilege, since it concerns the access rights granted to internal users","Encryption in transit, since it addresses how data moves across the networks","Ongoing due care, since third-party risk must be monitored continuously over time"], correct:3, explanation:"Continuous monitoring reflects ongoing due care; data minimization is unrelated here." },
  { id:70809, domain:4, level:1, question:"What is the purpose of a security baseline?", options:["Define the minimum required security configuration for a system or device type","List the maximum budget the security team may spend in a given fiscal year","Record the personal preferences of administrators for the system customization","Describe optional features that teams may enable only if they truly choose to"], correct:0, explanation:"A baseline sets the minimum required configuration, not an optional feature list." },
  { id:70810, domain:4, level:3, question:"Why is configuration drift a governance and risk concern?", options:["Drift always improves security by adding new undocumented features over time","Systems straying from approved baselines can introduce unmanaged vulnerabilities","Drift only affects user interface colors and never any real security settings","Drift is required by regulation and should be actively encouraged across systems"], correct:1, explanation:"Drift moves systems away from secure baselines, creating unmanaged exposure." },
  { id:70811, domain:4, level:3, question:"An auditor flags that backups are never tested. Which risk does this most directly create?", options:["Confidentiality of data in transit is exposed to passive network eavesdropping in practice","Vendors gain unauthorized access to the production payment card environment","Recovery may fail during a disaster, undermining continuity objectives like RTO","Employees lose the ability to use multifactor authentication when logging in"], correct:2, explanation:"Untested backups may fail at recovery time, threatening RTO, not data in transit." },
  { id:70812, domain:4, level:3, question:"A firm wants to demonstrate compliance to customers without sharing internal audit details. Which deliverable best fits?", options:["Its complete internal vulnerability scan results sent to every single customer in practice","Raw firewall configuration files emailed directly to each prospective customer","A list of all employee credentials to prove that access is properly controlled","An independent SOC 2 report that attests to controls without exposing internals"], correct:3, explanation:"A SOC 2 report provides external assurance without exposing sensitive internals." },
  { id:70813, domain:4, level:3, question:"During risk assessment, two risks have equal impact but very different likelihoods. How should prioritization proceed?", options:["The higher-likelihood risk generally warrants earlier attention given equal impact","Both should be ignored because their impacts happen to be exactly identical","The lower-likelihood risk should always be treated first regardless of impact in practice","Likelihood is irrelevant once the impact has been determined for each risk"], correct:0, explanation:"With equal impact, the higher-likelihood risk is generally prioritized first." },
  { id:70814, domain:4, level:1, question:"What is the purpose of a risk heat map?", options:["Display the physical temperature of the servers across the company data centers in practice","Visually communicate risks by plotting likelihood against impact for prioritization","Show the geographic locations of all remote employees on a single world map","List the encryption algorithms approved for protecting the data while at rest"], correct:1, explanation:"A heat map plots likelihood against impact to prioritize; it is not a temperature display." },
  { id:70815, domain:4, level:3, question:"Why should risk assessments be repeated periodically rather than performed once?", options:["Risks are static and never change once they have been initially identified now in practice","Repeating assessments is required only when an organization changes its name","The threat landscape, assets, and business context change continuously over time","A single assessment legally satisfies all compliance needs indefinitely now"], correct:2, explanation:"Risk changes over time, so assessments must repeat; risks are not static." },
  { id:70816, domain:4, level:2, question:"What is data residency in cloud compliance discussions?", options:["The encryption algorithm applied to data before it leaves the firm data center","The classification label assigned to data based on its real business sensitivity in practice","The number of replicas kept of each file across separate availability zones","The physical or geographic location where an organization data is actually stored"], correct:3, explanation:"Residency concerns where data is physically stored, not which cipher is applied." },
  { id:70817, domain:4, level:3, question:"A regulation requires that certain data never leave the country. A cloud provider replicates it globally by default. Best action?", options:["Configure region restrictions or choose a provider that guarantees data residency","Accept the global replication because cloud providers are inherently compliant in practice","Encrypt the data so the residency requirement no longer needs to be met now","Ignore the requirement because replication improves availability and the speed"], correct:0, explanation:"Region controls enforce residency; encryption alone does not satisfy a residency law." },
  { id:70818, domain:4, level:1, question:"What is the purpose of a records retention schedule?", options:["Ensure all records are kept forever regardless of legal or any business need","Define how long different record types are kept and when they are disposed of","Delete every record immediately after it is created to save the storage space","Encrypt records so that they can never be read by auditors or any regulators"], correct:1, explanation:"A retention schedule defines keep and disposal periods, not indefinite retention." },
  { id:70819, domain:4, level:3, question:"Keeping personal data far longer than necessary creates which primary risk?", options:["Improved compliance because more data always demonstrates better governance","Reduced storage costs because old data compresses more efficiently over time","Greater exposure and potential non-compliance with data minimization requirements","No risk at all, since retained data is automatically anonymized over the years in practice"], correct:2, explanation:"Excess retention increases exposure and breaches minimization; it is not auto-anonymized." },
  { id:70820, domain:4, level:2, question:"Why is phishing simulation a useful part of a security awareness program?", options:["It permanently prevents any phishing email from reaching employee inboxes now","It replaces the need for email filtering and other technical defensive controls","It is legally required of every organization across all global jurisdictions","It measures and improves employees ability to recognize real phishing attempts"], correct:3, explanation:"Simulations measure and build human resilience; they do not replace email filtering." },
  { id:70821, domain:4, level:2, question:"What is the governance value of role-based security training?", options:["It tailors training to the specific risks and duties of each distinct job function","It ensures every employee receives the exact same generic content for all roles in practice","It eliminates the need to ever update training as the threats evolve over time","It focuses solely on executives and excludes all of the other staff from it"], correct:0, explanation:"Role-based training matches content to job risk, unlike one-size-fits-all training." },
  { id:70822, domain:4, level:3, question:"After awareness training, phishing click rates stay high in one department. Best governance follow-up?", options:["Cancel all awareness training company-wide because it clearly does not work at all","Investigate that department specific risks and provide targeted reinforcement now","Punish the entire organization equally regardless of which group truly struggled","Assume the metric is wrong and simply stop measuring phishing susceptibility now"], correct:1, explanation:"Targeted reinforcement addresses the specific gap; cancelling all training is an overreaction." },
  { id:70823, domain:4, level:2, question:"What is the primary aim of the ISO/IEC 27001 certification process?", options:["Certify that a single firewall product blocks all known network attacks today in practice","Guarantee that the organization will never experience a data breach in future","Demonstrate that an organization ISMS meets recognized international requirements","Replace all national privacy laws with a single unified global standard now"], correct:2, explanation:"Certification shows the ISMS meets ISO requirements; it cannot guarantee no breach." },
  { id:70824, domain:4, level:2, question:"Which of these best describes the COSO framework primary focus?", options:["Wireless network encryption standards for the corporate office environments in practice","Cryptographic key management procedures for the cloud-based storage systems","Secure software development lifecycle practices for new mobile applications","Enterprise risk management and internal control over the organizational objectives"], correct:3, explanation:"COSO focuses on enterprise risk and internal control, not wireless encryption." },
  { id:70825, domain:4, level:2, question:"What does FAIR provide as a risk methodology?", options:["A model for quantifying information risk in financial terms for decision making","A catalog of malware signatures used by common endpoint detection products","A wireless protocol for securing communications between connected IoT devices","A certification proving that a vendor encrypts data while it is stored at rest in practice"], correct:0, explanation:"FAIR quantifies risk in financial terms; it is not a malware signature catalog." },
  { id:70826, domain:4, level:2, question:"NIST SP 800-30 specifically provides guidance on which activity?", options:["Sanitizing storage media before the disposal or reuse of the actual hardware in practice","Conducting risk assessments, including threat, vulnerability, and impact analysis","Handling and responding to computer security incidents step by step in order","Selecting cryptographic modules validated under the federal requirements now"], correct:1, explanation:"SP 800-30 guides risk assessments; media sanitization is covered by SP 800-88." },
  { id:70827, domain:4, level:3, question:"An organization must comply with both PCI-DSS and HIPAA. How should it approach overlapping controls?", options:["Build entirely separate, duplicate control sets that never share any evidence in practice","Comply with only the stricter framework and ignore the other one completely","Map common requirements once and apply unified controls to satisfy both regimes","Alternate compliance between the two frameworks in different calendar years"], correct:2, explanation:"Mapping shared requirements lets unified controls satisfy both, reducing duplication." },
  { id:70828, domain:4, level:2, question:"Which technique uses structured brainstorming with stakeholders to identify risks?", options:["Automated port scanning of every host on the organization internal network","Reading the vendor marketing brochures to assess their actual product security","Reviewing only the prior year financial statements for unusual anomalies now","Facilitated workshops drawing on diverse expertise to surface potential risks"], correct:3, explanation:"Facilitated workshops elicit risks from stakeholders; port scanning is a technical scan." },
  { id:70829, domain:4, level:2, question:"What is a threat in formal risk terminology?", options:["A potential cause of an unwanted incident that may harm a system or an asset","A weakness in a system that could be exploited by an external adversary now","The financial value assigned to a particular organizational asset before loss","A control implemented specifically to reduce the likelihood of harm occurring"], correct:0, explanation:"A threat is a potential cause of harm; a weakness that can be exploited is a vulnerability." },
  { id:70830, domain:4, level:2, question:"What is a vulnerability in formal risk terminology?", options:["An external actor intent and capability to cause harm to the target systems","A weakness that a threat could exploit to cause harm to an asset or a system","The dollar amount lost when a particular incident actually occurs in practice","A documented decision to accept a risk without applying any further mitigation"], correct:1, explanation:"A vulnerability is an exploitable weakness; an actor with intent is the threat." },
  { id:70831, domain:4, level:3, question:"Risk is most commonly expressed as a function of which combination?", options:["Asset value divided by the total number of employees in the whole organization in practice","The number of firewalls deployed multiplied by the routine patching frequency","Threat, vulnerability, and impact, often summarized as likelihood times impact now","The vendor revenue combined with the length of the signed service contract"], correct:2, explanation:"Risk combines threat, vulnerability, and impact; firewall counts are not the formula." },
  { id:70832, domain:4, level:2, question:"What is the purpose of a control gap when comparing current to target state?", options:["It measures the physical distance between two of the firm regional data centers","It records the salary difference between security and non-security staff members in practice","It encrypts the difference between two versions of a system configuration file","It identifies missing or weak controls that must be addressed to reach the target"], correct:3, explanation:"A control gap shows missing controls versus the target, not a physical distance." },
  { id:70833, domain:4, level:2, question:"What is a warm site in disaster recovery planning?", options:["A facility with some equipment and connectivity that needs setup before full use","A fully operational duplicate site ready to take over instantly with no delay","An empty building with no equipment, power, or any network connectivity at all","A cloud region that is used only for storing encrypted long-term archive backups"], correct:0, explanation:"A warm site has partial readiness needing setup; a hot site is instantly operational." },
  { id:70834, domain:4, level:2, question:"What is the key tradeoff between a hot site and a cold site?", options:["A cold site recovers faster and costs less than a hot site in every situation","A hot site recovers faster but costs more while a cold site is cheaper but slower","Both sites cost exactly the same and recover at an entirely identical speed","A hot site is always offline while a cold site is always fully operational now in practice"], correct:1, explanation:"Hot sites cost more for faster recovery; cold sites are cheaper but slower." },
  { id:70835, domain:4, level:3, question:"A business with a 1-hour RTO chooses a cold site to save money. What is the core problem?", options:["A cold site exceeds the RTO requirement by recovering far too quickly each time in practice","Cold sites are only a privacy concern and have no effect on the recovery time","A cold site cannot meet a 1-hour RTO because it requires lengthy setup time first","The RTO is irrelevant once any recovery site has been contractually secured"], correct:2, explanation:"A cold site needs long setup and cannot meet a 1-hour RTO; that is the mismatch." },
  { id:70836, domain:4, level:2, question:"Why should continuity plans designate clear roles and a succession order?", options:["To guarantee that only one specific person can ever authorize any recovery","To eliminate the need to test the plan through any exercises or drills at all in practice","To assign blame to specific individuals after an incident finally concludes","To ensure decisions can be made even if key personnel are unavailable at a time"], correct:3, explanation:"Succession ensures decisions continue if key staff are absent, not single-person reliance." },
  { id:70837, domain:4, level:2, question:"Why is it important to report risk in business terms to executives?", options:["Executives make resource decisions based on business impact, not technical jargon","Technical detail alone always persuades executives to fully fund security now in practice","Business framing hides the real risks so leaders approve far more spending","Executives are legally prohibited from receiving any technical information"], correct:0, explanation:"Business framing supports resource decisions; technical jargon alone is less actionable." },
  { id:70838, domain:4, level:3, question:"A security team reports only the count of blocked attacks to the board. Why is this metric weak for governance?", options:["It is the single most valuable governance metric and so needs no added context","It does not convey residual risk or business impact, limiting its decision value","It directly measures the organization compliance with every applicable regulation","It accurately predicts the exact date of the next major security data breach"], correct:1, explanation:"Blocked-attack counts lack risk and impact context, limiting their governance value." },
  { id:70839, domain:4, level:2, question:"What is the purpose of a balanced set of security metrics?", options:["Track only the number of firewall rules configured on the network perimeter in practice","Measure solely the size of the annual information security operating budget","Provide a rounded view across risk, compliance, operations, and effectiveness now","Report exclusively on incidents that have already caused some major losses"], correct:2, explanation:"Balanced metrics span multiple dimensions, unlike a single narrow firewall count." },
  { id:70840, domain:4, level:2, question:"Why include a breach notification clause in a vendor contract?", options:["To allow the vendor to conceal breaches to protect its own public reputation","To transfer all of your regulatory reporting duties onto the vendor alone now in practice","To guarantee that the vendor will never experience any security breach again","To require the vendor to promptly inform you when it suffers a relevant breach"], correct:3, explanation:"Notification clauses ensure timely awareness; they cannot guarantee no breaches occur." },
  { id:70841, domain:4, level:3, question:"A vendor stores your regulated data and suffers a breach but delays notifying you for 60 days. What failure is most evident?", options:["Inadequate contractual breach notification terms and weak vendor monitoring","Excessive encryption that prevented the vendor from detecting the breach early","Over-investment in your own internal incident response team capabilities","Too frequent auditing that overwhelmed the vendor security team resources"], correct:0, explanation:"A 60-day delay points to weak notification terms and monitoring, not over-encryption." },
  { id:70842, domain:4, level:2, question:"What is concentration risk in vendor management?", options:["The risk that a vendor office is located in a higher-crime urban area district in practice","Over-reliance on a single vendor whose failure would severely impact operations","The danger of distributing work across too many separate independent suppliers","The chance that a vendor will lower its prices and reduce its profit margins"], correct:1, explanation:"Concentration risk is heavy dependence on one vendor; spreading work reduces it." },
  { id:70843, domain:4, level:3, question:"Your organization relies on one cloud provider for all critical workloads. Which strategy best reduces concentration risk?", options:["Sign a longer contract with the same provider to lock in the current pricing","Move even more workloads to the same provider for greater operational simplicity in practice","Adopt a multi-cloud or documented exit strategy to avoid single-provider dependence","Stop assessing the provider since it already handles all of the critical systems"], correct:2, explanation:"Multi-cloud or an exit strategy reduces single-provider dependence; consolidating raises it." },
  { id:70844, domain:4, level:2, question:"What is the difference between a standard and a procedure?", options:["A procedure sets high-level intent while a standard lists only optional advice in practice","Both are non-mandatory and may be freely ignored by any employee at any time","A standard is written by end users while a procedure is set only by the board","A standard sets mandatory requirements while a procedure gives steps to meet them"], correct:3, explanation:"Standards define mandatory requirements; procedures give the steps to achieve them." },
  { id:70845, domain:4, level:2, question:"Why must policies be communicated and acknowledged by employees?", options:["Enforceability and accountability depend on staff being aware of the actual rules","Communication is unnecessary because ignorance excuses any policy violation","Only the legal department ever needs to read the organization policies fully in practice","Acknowledgment transfers all liability for breaches to individual employees"], correct:0, explanation:"Awareness underpins enforceability; ignorance does not excuse policy violations." },
  { id:70846, domain:4, level:3, question:"A new regulation conflicts with an existing internal standard. What is the appropriate governance action?", options:["Keep the internal standard because internal rules always outrank external law","Update the internal standard so it complies with the binding new regulation","Ignore both documents until the next scheduled annual policy review cycle","Delete the regulation reference so the internal standard appears compliant"], correct:1, explanation:"Binding regulation prevails, so the internal standard must be updated to comply." },
  { id:70847, domain:4, level:2, question:"What is the value of assigning a risk owner in the risk register?", options:["It guarantees the risk will be fully eliminated within a fixed short time period","It transfers the financial loss of the risk to the named individual personally","Accountability ensures someone is responsible for tracking and treating the risk","It allows the risk to be removed from the register without any treatment done"], correct:2, explanation:"Ownership creates accountability; it does not transfer personal financial liability." },
  { id:70848, domain:4, level:2, question:"Why should each risk in a register have a target treatment date?", options:["To ensure the risk is never actually treated before that single distant date","To transfer the risk automatically to an insurer on the specified target date in practice","To delete the risk from the register once the date has simply passed by now","To drive timely action and allow progress against the plan to be tracked over time"], correct:3, explanation:"Target dates drive timely action and tracking; they do not auto-transfer or delete risk." },
  { id:70849, domain:4, level:3, question:"A risk has been in treatment for two years with no progress and no updated date. What does this most likely indicate?", options:["A governance breakdown in risk tracking, ownership, or overall accountability","A perfectly healthy risk management process operating exactly as it is designed","That the risk has automatically resolved itself without any intervention at all","That the risk should be deleted immediately since some time has now elapsed"], correct:0, explanation:"Stalled treatment signals a tracking and accountability breakdown, not health." },
  { id:70850, domain:4, level:3, question:"Two controls each cost 10000 per year. Control A cuts ALE by 25000, Control B by 9000. If you pick one, which is better?", options:["Control B, because a smaller ALE reduction is always safer to implement first","Control A, because its net benefit of 15000 exceeds Control B net loss of 1000","Neither, because any control costing money should be avoided on basic principle","Both equally, because they share the same annual cost of ten thousand dollars"], correct:1, explanation:"Control A nets +15000 while B nets -1000, so A is the better single investment." },
  { id:70851, domain:4, level:3, question:"An ALE calculation yields a value far higher than the asset worth. What likely went wrong?", options:["ALE is supposed to always exceed the asset value, so nothing is wrong at all","The asset value must be doubled to make the ALE figure look more correct","The ARO or exposure factor was overstated, producing an unrealistic loss result","Quantitative analysis is invalid whenever the ALE turns out to be a large number"], correct:2, explanation:"An implausible ALE usually means an overstated ARO or EF, not a valid result." },
  { id:70852, domain:4, level:2, question:"Why might an organization combine qualitative and quantitative methods?", options:["Combining methods is strictly prohibited by every recognized risk framework now in practice","Quantitative analysis must always be discarded once qualitative work is done","Mixing methods guarantees the elimination of all residual organizational risk","Qualitative ranking can prioritize risks before costly quantitative analysis runs"], correct:3, explanation:"Qualitative triage can focus expensive quantitative work; the two are complementary." },
  { id:70853, domain:4, level:2, question:"What is the typical responsibility of a Chief Information Security Officer?", options:["Lead the organization information security strategy, risk, and governance program","Personally configure every server and network device in the main data center in practice","Approve the marketing budget for all of the company external product lines","Write the source code for each application that the organization deploys now"], correct:0, explanation:"A CISO leads security strategy and governance, not hands-on device configuration." },
  { id:70854, domain:4, level:2, question:"What is the purpose of a RACI matrix in governance?", options:["Encrypt project documents so that only certain managers can read their contents in practice","Clarify who is responsible, accountable, consulted, and informed for given tasks","Rank vendors by their price across several competing managed service categories","Measure the network latency between two distant corporate office locations"], correct:1, explanation:"A RACI matrix clarifies roles and accountability, not document encryption." },
  { id:70855, domain:4, level:3, question:"A security initiative stalls because no one knows who must approve key decisions. Which tool most directly addresses this?", options:["A network diagram showing how the firewalls segment internal traffic zones","A data classification scheme labeling all information by its sensitivity level in practice","A RACI matrix that assigns accountability and approval roles for the initiative","An encryption policy specifying algorithms for protecting all the stored data"], correct:2, explanation:"A RACI matrix assigns approval and accountability, resolving the decision gap." },
  { id:70856, domain:4, level:2, question:"What is an attestation in the context of compliance reporting?", options:["A marketing claim made by a vendor about its own product security capabilities in practice","A list of employee passwords proving that access is properly restricted now","An internal memo that bypasses the need for any independent assessment at all","A formal statement by an auditor about whether controls meet specified criteria"], correct:3, explanation:"An attestation is an auditor formal statement on controls, not a marketing claim." },
  { id:70857, domain:4, level:2, question:"Why is sampling commonly used during audits?", options:["Examining a representative subset is practical when testing every item is infeasible","Sampling guarantees that every single transaction is individually reviewed now in practice","Auditors use sampling specifically to avoid finding any control deficiencies","Sampling is required because audits are legally forbidden from reviewing data"], correct:0, explanation:"Sampling tests a representative subset when full testing is impractical." },
  { id:70858, domain:4, level:3, question:"An auditor samples 30 of 10000 transactions and finds 3 errors. What is the most appropriate next step?", options:["Conclude the controls are perfect because most transactions were not tested","Expand the sample or investigate, since the error rate suggests a control issue","Ignore the errors because they represent a small fraction of all transactions","Immediately certify full compliance based solely on the limited sample reviewed"], correct:1, explanation:"A 10 percent error rate warrants expanded testing, not ignoring or certifying." },
  { id:70859, domain:4, level:3, question:"A breach affects 500 EU residents. Under GDPR, what is a key obligation regarding the supervisory authority?", options:["Wait at least one full year before notifying to confirm the full scope of impact","Notify only if the company chooses to, since reporting is entirely voluntary","Notify the authority without undue delay, typically within 72 hours of awareness","Avoid any notification to protect the organization valuable brand reputation"], correct:2, explanation:"GDPR requires notifying the authority within about 72 hours; it is not voluntary." },
  { id:70860, domain:4, level:2, question:"What is consent in the context of lawful data processing?", options:["An assumption that users agree simply by visiting a public website one time in practice","A clause that lets the organization process any data for any future purpose","A contract between two vendors that excludes the data subject entirely now","A freely given, specific, informed agreement by the individual to process the data"], correct:3, explanation:"Valid consent is freely given, specific, and informed, not a mere visit assumption." },
  { id:70861, domain:4, level:3, question:"An app pre-checks a consent box to opt users into data sharing by default. Why is this problematic under modern privacy law?", options:["Consent must be a clear affirmative action and pre-checked boxes are not valid","Pre-checked boxes are the strongest possible form of explicit user consent now","Default opt-in is required by privacy regulations to maximize data collection","Consent is irrelevant because apps are exempt from all data protection rules"], correct:0, explanation:"Consent requires a clear affirmative act; pre-checked boxes do not qualify as valid." },
  { id:70862, domain:4, level:2, question:"Why is patch and dependency management part of supply chain risk governance?", options:["Third-party components never contain any vulnerabilities once they are installed in practice","Vulnerable third-party components can be exploited to compromise your own systems","Patching dependencies always breaks applications and so should be avoided now","Dependency risk only matters for hardware and never for any software libraries"], correct:1, explanation:"Vulnerable dependencies are exploitable supply chain risk; they do contain flaws." },
  { id:70863, domain:4, level:3, question:"A critical zero-day is announced in a library used across many of your apps. Which artifact most speeds your response?", options:["A printed copy of the company acceptable use policy for all of the employees in practice","The marketing roadmap describing the upcoming product feature releases soon","An accurate software bill of materials revealing exactly where the library is used","A list of every vendor office address and their main contact phone numbers"], correct:2, explanation:"An SBOM pinpoints where the vulnerable library is used, accelerating response." },
  { id:70864, domain:4, level:1, question:"What is compliance in an information security context?", options:["Eliminating every possible vulnerability from all the systems permanently now","Encrypting all data with a single algorithm chosen by the IT department alone","Transferring all security responsibilities to an external managed provider now in practice","Adhering to laws, regulations, standards, and policies that apply to the organization"], correct:3, explanation:"Compliance means adhering to applicable rules; it is not eliminating all vulnerabilities." },
  { id:70865, domain:4, level:1, question:"What is governance in an information security context?", options:["The system of policies, roles, and oversight that directs and controls the security","The act of installing antivirus software on every single employee workstation","A one-time penetration test performed just before a product is finally released in practice","The encryption of all network traffic between two corporate office locations"], correct:0, explanation:"Governance is the system of policies, roles, and oversight, not a one-time pentest." },
  { id:70866, domain:4, level:1, question:"What is the purpose of an information security policy framework?", options:["Replace the need for any technical security controls within the organization now in practice","Provide a structured hierarchy of policies, standards, procedures, and guidelines","List the personal contact information of every employee in the whole company","Define the marketing strategy for promoting the organization various products"], correct:1, explanation:"A policy framework structures the document hierarchy; it does not replace controls." },
  { id:70867, domain:4, level:2, question:"Why is asset inventory foundational to risk management?", options:["Asset inventories are only useful for the accounting department records keeping","Inventories eliminate the need to classify or assess any of those same assets","You cannot protect or assess risk for assets you do not know that you have now","Knowing your assets automatically removes all the risk associated with them"], correct:2, explanation:"You cannot protect unknown assets, so inventory underpins risk management." },
  { id:70868, domain:4, level:2, question:"How does data classification support compliance efforts?", options:["It guarantees that all data is automatically deleted after its classification in practice","It removes the obligation to comply with any data protection regulations now","It assigns all data the very same protection level to simplify management","It ensures regulated data is identified and protected per its actual requirements"], correct:3, explanation:"Classification identifies regulated data for proper protection, not blanket deletion." },
  { id:70869, domain:4, level:3, question:"An organization classifies all data as confidential to be safe. What is the main drawback?", options:["Over-classification wastes resources and dilutes focus on truly sensitive data","Over-classification perfectly optimizes the use of all the security resources","It guarantees regulatory compliance across every applicable global jurisdiction","It removes the need to apply any access controls to the classified data now"], correct:0, explanation:"Treating everything as confidential wastes resources and dilutes real protection." },
  { id:70870, domain:4, level:2, question:"What is the purpose of a third-party risk tiering model?", options:["Ensure every vendor receives an identical, maximum-depth security assessment","Allocate assessment effort based on the risk each vendor poses to the organization","Rank vendors solely by the lowest price they offer for their managed services in practice","Assign each vendor to a tier based on the alphabetical order of its name only"], correct:1, explanation:"Tiering scales effort to vendor risk, not identical depth or alphabetical order." },
  { id:70871, domain:4, level:3, question:"A low-risk vendor and a high-risk vendor receive identical light assessments. What is the governance flaw?", options:["The approach is ideal because consistency matters far more than the actual risk in practice","The low-risk vendor is being over-assessed and should receive no review at all","Risk-based tiering is not applied, leaving the high-risk vendor under-assessed now","Tiering should rank vendors only by contract value, not by their actual risk"], correct:2, explanation:"Identical light reviews under-assess the high-risk vendor; tiering should scale effort." },
  { id:70872, domain:4, level:2, question:"Why are continuous monitoring programs valuable in governance?", options:["They replace the need to ever perform any formal audits or assessments again in practice","They only matter for compliance and have no effect on the actual real risk","They guarantee that no control will ever fail once monitoring is first begun","They provide ongoing assurance that controls remain effective between the audits"], correct:3, explanation:"Continuous monitoring gives assurance between audits; it does not guarantee no failures." },
  { id:70873, domain:4, level:2, question:"What does shared responsibility mean in cloud compliance?", options:["Security duties are split between the cloud provider and customer by service model","The cloud provider assumes complete responsibility for all customer security","The customer is solely responsible for securing the provider data centers fully in practice","Responsibility is shared equally with every other tenant on the same platform"], correct:0, explanation:"Shared responsibility divides duties between provider and customer by service model." },
  { id:70874, domain:4, level:3, question:"In IaaS, who is generally responsible for patching the guest operating system?", options:["The cloud provider, because it owns the underlying physical server hardware","The customer, because IaaS gives them control of the operating system and above","No one, because IaaS operating systems never require any security patches now","An independent auditor, who patches the systems as part of the assessment work in practice"], correct:1, explanation:"In IaaS the customer manages the guest OS, including its patching responsibilities." },
  { id:70875, domain:4, level:2, question:"What is the purpose of a security exception or risk acceptance process?", options:["Allow employees to bypass any policy quietly without leaving any record at all","Eliminate the policy entirely whenever it becomes inconvenient to follow now","Formally document and approve deviations from policy with clear accountability","Transfer all responsibility for the deviation to an external independent auditor"], correct:2, explanation:"An exception process documents and approves deviations, not silent bypasses." },
  { id:70876, domain:4, level:3, question:"A team requests a permanent exception to a critical control with no expiry or review. Why is this a concern?", options:["Permanent exceptions are best practice because they reduce administrative overhead","Exceptions should never have an owner since the policy already covers everything","Reviewing exceptions wastes effort because approved risks never change over time","Exceptions without expiry or review can hide growing, unmanaged risk indefinitely"], correct:3, explanation:"Open-ended exceptions hide drifting risk; they should have expiry and review dates." },
  { id:70877, domain:4, level:2, question:"What is the purpose of a code of conduct or ethics policy?", options:["Set expected behavioral standards and ethical obligations for personnel members","Define the firewall rules that govern traffic between the various network segments","Specify the encryption algorithm used for protecting all data while in transit","List the vendors approved for purchasing office supplies and other equipment"], correct:0, explanation:"A code of conduct sets behavioral and ethical standards, not firewall rules." },
  { id:70878, domain:4, level:2, question:"Why is whistleblower protection relevant to governance and compliance?", options:["It allows the organization to ignore reports of fraud and other wrongdoing now in practice","It encourages the reporting of misconduct without any fear of later retaliation","It transfers legal liability for misconduct onto the person who reports it","It is only relevant to the marketing department and not to security at all"], correct:1, explanation:"Whistleblower protection encourages misconduct reporting by preventing retaliation." },
  { id:70879, domain:4, level:2, question:"What is the main purpose of an enterprise risk management program?", options:["Address only cybersecurity risks while ignoring all of the other risk categories in practice","Eliminate every operational, financial, and strategic risk permanently and fully","Integrate risk management across the whole organization to support its objectives","Replace the finance department budgeting and its forecasting functions entirely"], correct:2, explanation:"ERM integrates risk management enterprise-wide, not just cybersecurity alone." },
  { id:70880, domain:4, level:3, question:"How does cyber risk fit within enterprise risk management?", options:["As a completely separate concern that ERM should never have to consider at all in practice","As the only risk category that an ERM program is permitted to actually address","As a purely technical issue with no relevance to any business objectives now","As one category of risk that must be integrated with strategic and operational risk"], correct:3, explanation:"Cyber risk is one ERM category integrated with other risks, not wholly separate." },
  { id:70881, domain:4, level:2, question:"What is the purpose of risk aggregation in an ERM context?", options:["Combine related risks to understand total exposure across the whole organization","Split each risk into many tiny pieces to make them appear far less significant","Hide individual risks from leadership by merging them into one combined figure","Assign each aggregated risk to a different unrelated business unit for tracking in practice"], correct:0, explanation:"Aggregation reveals total exposure across related risks, not concealment of them." },
  { id:70882, domain:4, level:3, question:"Several business units each accept a minor risk, but combined they exceed corporate appetite. What concept is this?", options:["Risk transference, since the units have insured against the combined potential loss","Aggregate risk exceeding tolerance even when individual risks seem acceptable now","Risk avoidance, since each unit declined to engage in the risky activity fully","Separation of duties, since the risk is split across multiple business units"], correct:1, explanation:"Individually small risks can aggregate beyond appetite; that is aggregate risk." },
  { id:70883, domain:4, level:2, question:"What is the role of a compliance officer in an organization?", options:["Personally write all of the application code that enforces the access controls","Manage the physical landscaping and the maintenance of the office grounds now","Oversee adherence to laws, regulations, and internal policies across the whole firm","Set the retail pricing for the products the organization sells to its customers in practice"], correct:2, explanation:"A compliance officer oversees adherence to rules, not application coding." },
  { id:70884, domain:4, level:2, question:"Why is documentation of controls important for both audits and operations?", options:["Documentation is only needed to satisfy auditors and serves no other purpose in practice","Documenting controls automatically makes them effective without any testing","Controls function identically whether or not they are documented at all now","It provides evidence of control existence and supports consistent operation of them"], correct:3, explanation:"Documentation evidences controls and supports consistency; it is not auditor-only." },
  { id:70885, domain:4, level:2, question:"What is a control objective?", options:["A statement of the intended result that a control is meant to achieve overall","The exact technical configuration of a single firewall rule on the perimeter","The dollar value of the asset that a particular control is meant to protect","A list of every employee authorized to access a specific business application"], correct:0, explanation:"A control objective states the intended outcome, not a specific firewall rule." },
  { id:70886, domain:4, level:3, question:"An organization has many documented controls but cannot show they actually operate. What is the governance gap?", options:["Too few controls have been documented to satisfy any recognized framework","Lack of control monitoring and evidence of their real operating effectiveness","Excessive control effectiveness that overwhelms the entire audit process now in practice","Over-reliance on technical controls instead of any supporting documentation"], correct:1, explanation:"The gap is missing operating evidence and monitoring, not too few documents." },
  { id:70887, domain:4, level:2, question:"What is the difference between a preventive and a detective control?", options:["Detective controls stop incidents while preventive controls only report them later in practice","Both control types only function after an incident has already fully occurred","Preventive controls stop incidents while detective controls identify them afterward","Preventive controls apply to people while detective controls apply to systems"], correct:2, explanation:"Preventive controls stop incidents; detective controls find them after the fact." },
  { id:70888, domain:4, level:2, question:"Which is an example of a corrective control?", options:["Requiring a password before a user is allowed to log in to an application","Logging all administrative actions for later review by the security staff team","Installing a fence around the perimeter of the data center facility grounds","Restoring systems from backup after a ransomware incident has already occurred"], correct:3, explanation:"Restoring from backup is corrective; requiring a password is preventive instead." },
  { id:70889, domain:4, level:3, question:"A regulation requires a control your environment cannot technically support. What is the appropriate response?", options:["Implement a documented compensating control that meets the regulation real intent","Ignore the requirement because the exact control is not technically feasible now in practice","Falsify the audit evidence to make it appear the control is properly in place","Wait indefinitely for the regulation to change before taking any action at all"], correct:0, explanation:"A documented compensating control can meet the intent when the exact control is infeasible." },
  { id:70890, domain:4, level:2, question:"What is the purpose of a compensating control?", options:["Replace all required controls permanently to reduce ongoing operational costs","Provide an alternative safeguard when a required control cannot be implemented","Eliminate the need to comply with the underlying regulatory requirement now","Document a risk acceptance so that no safeguard is needed at all going forward"], correct:1, explanation:"A compensating control substitutes when the required one cannot be implemented directly." },
  { id:70891, domain:4, level:2, question:"Why must compensating controls be documented and approved?", options:["So that the organization can later deny that the control ever truly existed","Because compensating controls require no oversight once they are deployed now","To demonstrate that the alternative meets the requirement intent and is sanctioned","To transfer the entire compliance obligation onto an external third-party auditor in practice"], correct:2, explanation:"Documentation and approval show the alternative meets intent and is sanctioned." },
  { id:70892, domain:4, level:1, question:"What does the acronym GRC stand for?", options:["Global Risk Calculation, a single formula for quantifying every possible risk","General Regulatory Code, a unified law covering all industries across the world in practice","Guaranteed Recovery Capability, a measure of the disaster recovery success rate","Governance, Risk, and Compliance, the integrated discipline of managing all three"], correct:3, explanation:"GRC is Governance, Risk, and Compliance, not a single risk formula." },
  { id:70893, domain:4, level:2, question:"Why integrate governance, risk, and compliance rather than manage them separately?", options:["Integration reduces duplication and aligns activities toward common objectives now","Separate management always produces better outcomes than any integration would in practice","Integration is prohibited by most recognized security and audit frameworks now","Combining them removes the need to ever assess risk or verify compliance again"], correct:0, explanation:"Integration cuts duplication and aligns efforts; separation often creates silos." },
  { id:70894, domain:4, level:2, question:"What is a maturity model used for in a security program?", options:["Calculate the exact monetary loss expected from a single security incident in practice","Assess and improve the capability of processes against defined maturity levels","List the malware signatures detected on the organization various endpoints","Encrypt the organization policy documents using one shared symmetric key"], correct:1, explanation:"Maturity models gauge and improve process capability, not compute incident loss." },
  { id:70895, domain:4, level:3, question:"A program scores initial or ad hoc on a maturity model. What does this most likely indicate?", options:["Processes are fully optimized and continuously improving across the organization in practice","The program has already reached the highest possible level of process maturity","Processes are unstructured and inconsistent, lacking repeatable defined practices","Maturity models cannot apply to information security programs in any case now"], correct:2, explanation:"An initial score means unstructured, inconsistent processes, not optimized ones." },
  { id:70896, domain:4, level:2, question:"What is the benefit of benchmarking a security program against peers?", options:["It guarantees the organization is more secure than all of its direct competitors in practice","It removes the need to perform any internal risk assessments going forward now","It legally certifies the organization as compliant with all relevant regulations","It provides context for whether investment and maturity are appropriate for sector"], correct:3, explanation:"Benchmarking gives context on investment and maturity; it does not guarantee superiority." },
  { id:70897, domain:4, level:2, question:"Why is board-level reporting on cyber risk increasingly expected?", options:["Cyber risk is a material business risk requiring oversight and accountability now","Boards are required to personally configure the organization perimeter firewalls in practice","Reporting to the board transfers all of the cyber liability onto its members","Board oversight eliminates the need for any operational security controls now"], correct:0, explanation:"Cyber risk is material business risk needing board oversight, not hands-on config." },
  { id:70898, domain:4, level:3, question:"A board asks whether the company cyber risk is within appetite. What best answers this?", options:["A raw list of every single vulnerability detected during the last network scan in practice","A report comparing current residual risk against the formally defined risk appetite","The total number of security alerts generated in the past full calendar month","A copy of the firewall rule base exported directly from the perimeter device"], correct:1, explanation:"Comparing residual risk to appetite answers the question; raw scans lack that context." },
  { id:70899, domain:4, level:2, question:"What is the purpose of a third-party SOC 1 report?", options:["Attest to the security and availability of a cloud platform infrastructure only in practice","Certify that a product encrypts data using an approved strong cipher suite now","Provide assurance over controls relevant to a service impact on financial reporting","List the personal data subject rights granted under a given privacy regulation"], correct:2, explanation:"SOC 1 addresses controls affecting financial reporting; SOC 2 covers security criteria." },
  { id:70900, domain:4, level:3, question:"You need assurance over a payroll provider controls affecting your financial statements. Which report fits best?", options:["A SOC 2 report, which addresses security, availability, and related trust criteria","A SOC 3 report, which is a short general-use summary without any real detail","An ISO 9001 certificate, which covers only quality management processes broadly","A SOC 1 report, which addresses controls relevant to financial reporting matters"], correct:3, explanation:"SOC 1 covers financial-reporting controls, fitting a payroll provider engagement." },
];
if (typeof window !== 'undefined') window.QUESTIONS_SECX_C4 = QUESTIONS_SECX_C4;
